const t=[{id:"1",title:"Embedded Design and Manufacturing Methods for 3D Printed Smart Sensing Orthosis",period:"Oct 2023 – Present",venue:"Work under review at IEEE Robotics and Automation Letters",collaboration:"Renji Hospital Collaboration",shortSummary:"3D printed monolithic smart sensing orthosis for scoliosis correction with real-time pressure feedback.",image:"/projects/1.jpg",overview:"Focused on developing a 3D printed, monolithic smart sensing orthosis for scoliosis correction.",contributions:["Piezoresistive Sensor Development & Integration: Devised generative design for piezoresistive sensors; engineered monolithic sensor-orthosis integration via multi-material 3D printing.","Clinically-Informed Orthosis Design Framework: Led doctor-orthotist-patient collaboration to optimize therapeutic function and comfort; deployed anatomical stress-targeted sensor matrices.","Authorship: Authored and drafted the paper, synthesizing research findings; designed figures and visualizations to effectively communicate complex concepts."],keyOutcomes:["Optimized piezoresistive sensors with enhanced stability/performance.","Validated co-design framework.","Demonstrated method for treatment optimization via real-time pressure data."],gallery:["/projects/12.png","/projects/13.png","/projects/14.png","/projects/15.png","/projects/16.png"]},{id:"2",title:"Scoliodect: A Rapid Wearable Device for Detecting Adolescent Scoliosis",period:"Sept 2024 – Sept 2025",venue:"The James Dyson Award (International Top 20 & Top 3 in China Mainland)",website:"https://www.jamesdysonaward.org/en-GB/2025/project/scoliodetect",shortSummary:"Wearable device for rapid scoliosis detection with 3-degree precision and >50% higher accuracy than traditional methods.",image:"/projects/2.jpg",overview:"Scoliodect is a wearable device designed for rapid and accurate scoliosis detection. It measures spinal curvature with 3-degree precision, offering over 50% more accuracy than traditional methods.",contributions:["Prototype Design: Designed and prototyped a wearable device, ensuring user comfort and accurate detection.","Data Collection: Conducted critical data collection involving over 200 subjects to train and optimize the model.","Algorithm Development: Created a spinal motion-morphology correlation framework for scoliosis detection."],keyOutcomes:["Functional prototype demonstrating >50% higher accuracy than traditional methods.","Developed robust detection algorithm.","Established critical dataset."],gallery:["/projects/22.png","/projects/23.png","/projects/24.png","/projects/25.png","/projects/26.png"]},{id:"3",title:"EMG and MMG Data Acquisition for Hand Spasticity",period:"Oct 2023 – Oct 2024",venue:"Academic Papers Under Review",collaboration:"Shanghai First Rehabilitation Hospital Collaboration",shortSummary:"sEMG and MMG data acquisition system for hand spasticity assessment, linking signals to clinical MAS scores.",image:"/projects/3.jpg",overview:"Developed a data acquisition system using sEMG and MMG technologies to assess hand spasticity in patients, integrating signal acquisition with clinical assessments to improve diagnosis and treatment.",contributions:["Hardware Prototyping: Designed and built EMG and MMG data acquisition devices.","Clinical Data Collection: Gathered 200+ samples, creating a comprehensive dataset.","Data Modeling: Developed models linking EMG/MMG signals to spasticity levels (MAS scores).","Ethical Review: Drafted consent forms and secured ethical approval for data collection."],keyOutcomes:["Validated data acquisition system.","High-accuracy spasticity grading model.","Clinical-grade MMG prototype."],gallery:["/projects/31.png","/projects/32.png"]},{id:"4",title:"Placemaking Dynamics Simulation Tool with LLM-based Multi-Agent Social Simulation",period:"Jun 2025 – Present",venue:"CHI'26 DIS'26",collaboration:"Tongji University Collaboration",shortSummary:"LLM and multi-agent simulation tool for placemaking design, supporting lateral diversity and longitudinal behavior evolution.",image:"/projects/4.jpg",overview:"Developed a tool combining LLMs and multi-agent social simulations to support designers in addressing challenges related to lateral diversity and longitudinal behavioral evolution in placemaking.",contributions:["Front-End Design and Development: Developed an intuitive interface aligned with user requirements, ensuring ease of use and engagement.","User Studies: Conducted comprehensive studies to assess tool effectiveness, gathering and analyzing designer feedback to optimize engagement.","Co-authorship: Co-authored the research paper, summarizing the findings, design insights, and implications for future placemaking practices."],keyOutcomes:["Interactive prototype for simulating spatial design impacts.","Insights into LLM applications for speculative placemaking design."],gallery:["/projects/41.png","/projects/42.png","/projects/43.png"]}];function o(e){return t.find(i=>i.id===e)}export{o as g,t as r};
